queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?column_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasColumns ?child ; p:hasMagazines ?parent . } GROUP BY ?child }
  ?child p:column_name ?column_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Magazines } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?column_name WHERE {
  ?magazines_columns a :Magazines_Columns .
  ?columns a :Columns .
  ?magazines_columns p:hasColumns ?columns .
  ?magazines a :Magazines .
  ?magazines_columns p:hasMagazines ?magazines .
  ?magazines p:name ?name .
  ?columns p:column_name ?column_name .
} }
  collective: { SELECT ?column_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasColumns ?child ; p:hasMagazines ?parent . } GROUP BY ?child }
  ?child p:column_name ?column_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Magazines } }
  FILTER(?nf = ?total)
} }
}
